variables.summaryQuery:
[concat('let look = ', parameters('lookbackDays'), 'd;
let tiers = _GetWatchlist("', parameters('watchlistAlias'), '") | project TableName = tostring(column_ifexists("TableName", "")), WTier = tostring(column_ifexists("Tier", "DataLakeOnly"));
let cur = Usage | where TimeGenerated > ago(look) | where IsBillable == true | summarize GB = sum(Quantity)/1000 by DataType;
let prev = Usage | where TimeGenerated between (ago(look*2) .. ago(look)) | where IsBillable == true | summarize pGB = sum(Quantity)/1000 by DataType;
cur
| join kind=leftouter prev on DataType
| join kind=leftouter tiers on $left.DataType == $right.TableName
| extend tier = iff(isnotempty(WTier), "LakeOnly", "Analytics")
| summarize analyticsGB = round(sumif(GB, tier == "Analytics"), 2), analyticsPrevGB = round(sumif(pGB, tier == "Analytics"), 2), lakeGB = round(sumif(GB, tier == "LakeOnly"), 3), lakePrevGB = round(sumif(pGB, tier == "LakeOnly"), 3), totalTables = dcount(DataType), lakeOnlyCount = dcountif(DataType, tier == "LakeOnly")
| extend analyticsDelta = round(iff(analyticsPrevGB > 0, (analyticsGB - analyticsPrevGB)/analyticsPrevGB*100, 9999.0), 1), lakeDelta = round(iff(lakePrevGB > 0, (lakeGB - lakePrevGB)/lakePrevGB*100, 9999.0), 1)')]

Compose_agent_prompt.inputs:
Use UsageCostReportInsightAgent to analyze the following Sentinel usage data and produce the insight labels. Numbers are already computed deterministically; quote them verbatim and never recalculate. Respond in @{parameters('outputLanguage')}.

[TOTALS]
analyticsGB=@{coalesce(outputs('Compose_summary')?['analyticsGB'],0)} analyticsDelta=@{coalesce(outputs('Compose_summary')?['analyticsDelta'],0)}% lakeGB=@{coalesce(outputs('Compose_summary')?['lakeGB'],0)} lakeDelta=@{coalesce(outputs('Compose_summary')?['lakeDelta'],0)}% totalTables=@{coalesce(outputs('Compose_summary')?['totalTables'],0)} lakeOnlyCount=@{coalesce(outputs('Compose_summary')?['lakeOnlyCount'],0)}

[CANDIDATES] (columns: tableName | tier | currentGB | deltaPercent | lastSeen | reason)
@{join(body('Select_candidate_lines'), decodeUriComponent('%0A'))}
